import numpy as np

# {Implement an adaptive weight-based routing strategy that dynamically balances travel time, customer priority, and time window constraints using updated environmental inputs and predefined heuristics to efficiently minimize route completion.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    min_weighted_cost = float('inf')
    best_node = None

    importance_factor = np.array([5 * (1 - (current_time / (end_time + 0.01))) for _, end_time in time_windows])  # vary weights based on time window urgency

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_time, end_time = time_windows[i]
        wait_time = max(0, start_time - arrival_time)

        penalty = max(0, 1000 * (arrival_time - end_time))  # penalize based on how late the arrival is

        cost = travel_time + wait_time
        weighted_cost = importance_factor[i] * cost + penalty

        if weighted_cost < min_weighted_cost:
            min_weighted_cost = weighted_cost
            best_node = i

    return best_node
